#include <WiFi.h>
#include <WebServer.h>

WebServer server(80);
const int relayPins[] = {12, 13, 14, 15};

void handleRoot() {
  server.send(200, "text/html", "<h1>ESP32 Relay Web Server</h1><a href='/on'>Relay 1 ON</a><br><a href='/off'>Relay 1 OFF</a>");
}

void setup() {
  for(int i=0; i<4; i++) {
    pinMode(relayPins[i], OUTPUT); digitalWrite(relayPins[i], HIGH); // Active LOW relays
  }
  server.on("/", handleRoot);
  server.begin();
}

void loop() {
  server.handleClient();
}

#include <Wire.h>
#include <Adafruit_ADS1X15.h>

Adafruit_ADS1115 ads;

void setup() {
  Serial.begin(115200);
  ads.begin();
}

void loop() {
  int16_t rawCurrent = ads.readADC_SingleEnded(0);
  double voltage = rawCurrent * 0.1875 / 1000.0; // FS = 6.144V
  double current = voltage * 30.0; // 30A / 1V output ratio
  Serial.printf("Current: %.2f A, Estimated Power: %.1f W\n", current, current * 230.0);
  delay(1000);
}

#include <WiFi.h>
#include <PubSubClient.h>
#include <DHT.h>

WiFiClient espClient;
PubSubClient client(espClient);
DHT dht(4, DHT22);

void setup() {
  client.setServer("broker.hivemq.com", 1883);
  dht.begin();
}

void loop() {
  if (!client.connected()) {
    client.connect("ESP32Client");
  }
  client.loop();

  float t = dht.readTemperature();
  char msg[10];
  dtostrf(t, 4, 2, msg);
  client.publish("ee/sensors/temp", msg);
  delay(5000);
}

